def _ccr_floor1_trade() -> Trade:
    """Return the single B31-CCR-FLOOR-1 trade instance (5y GBP IR derivative)."""
    return make_trade(
        trade_id=CCR_FLOOR1_TRADE_ID,
        netting_set_id=CCR_FLOOR1_NETTING_SET_ID,
        asset_class=CCR_FLOOR1_ASSET_CLASS,
        transaction_type=CCR_FLOOR1_TRANSACTION_TYPE,
        notional=CCR_FLOOR1_NOTIONAL,
        currency=CCR_FLOOR1_CURRENCY,
        maturity_date=CCR_FLOOR1_MATURITY_DATE,
        start_date=CCR_FLOOR1_START_DATE,
        delta=CCR_FLOOR1_DELTA,
        is_long=CCR_FLOOR1_IS_LONG,
        mtm_value=CCR_FLOOR1_MTM,
    )


def _ccr_floor1_netting_set() -> NettingSet:
    """Return the single B31-CCR-FLOOR-1 netting set instance."""
    return NettingSet(
        netting_set_id=CCR_FLOOR1_NETTING_SET_ID,
        counterparty_reference=CCR_FLOOR1_COUNTERPARTY_REF,
        is_legally_enforceable=CCR_FLOOR1_IS_LEGALLY_ENFORCEABLE,
        is_margined=CCR_FLOOR1_IS_MARGINED,
    )


