def create_ccr_floor1_trades() -> pl.DataFrame:
    """Return the single-row trades DataFrame for B31-CCR-FLOOR-1."""
    return create_trades([_ccr_floor1_trade()])


def create_ccr_floor1_netting_sets() -> pl.DataFrame:
    """Return the single-row netting-sets DataFrame for B31-CCR-FLOOR-1."""
    return create_netting_sets([_ccr_floor1_netting_set()])


def create_ccr_floor1_margin_agreements() -> pl.DataFrame:
    """Return a zero-row margin-agreements DataFrame (B31-CCR-FLOOR-1: unmargined)."""
    return create_margin_agreements([])


def create_ccr_floor1_collateral() -> pl.DataFrame:
    """Return a zero-row CCR-collateral DataFrame (B31-CCR-FLOOR-1: no collateral)."""
    return pl.DataFrame(schema=dtypes_of(CCR_COLLATERAL_SCHEMA))


# ---------------------------------------------------------------------------
# Private portfolio-stub builders
# ---------------------------------------------------------------------------


def _build_cp_ccr_1_counterparty() -> pl.LazyFrame:
    """
    Return a one-row counterparty LazyFrame for CP_CCR_1.

    CP_CCR_1 is a GB institution with CQS 2.  entity_type="institution" drives
    the Classifier to ExposureClass.INSTITUTION → SA risk weight look-up via
    B31 Art. 120(2) Table 3 (CQS 2 → 30% under ECRA).

    institution_cqs=2 is set directly so the SA calculator resolves the
    correct 30% risk weight even when bypassing the full rating-inheritance
    pipeline in unit tests.  The matching external rating row carries the same
    CQS 2 for full-pipeline resolution.

    No IRB model permission is provided.  This is the pure-SA CCR case
    (S-TREA == U-TREA) that the output-floor S-TREA/U-TREA inclusion test pins.
    """
    row = {
        "counterparty_reference": CCR_FLOOR1_COUNTERPARTY_REF,
        "counterparty_name": "B31-CCR-FLOOR-1 Test Institution (CQS 2, SA-only)",
        "entity_type": CCR_FLOOR1_CP_ENTITY_TYPE,
        "country_code": CCR_FLOOR1_CP_COUNTRY_CODE,
        "default_status": False,
        "apply_fi_scalar": False,
        "is_managed_as_retail": False,
        "institution_cqs": CCR_FLOOR1_RATING_CQS,
    }
    return pl.DataFrame([row], schema=dtypes_of(COUNTERPARTY_SCHEMA)).lazy()


def _build_cp_ccr_1_rating() -> pl.LazyFrame:
    """
    Return a one-row external ratings LazyFrame for CP_CCR_1.

    S&P "A" = CQS 2 under B31 ECRA mapping for institutions.
    B31 Art. 120(2) Table 3: institution CQS 2 → 30% risk weight.
    is_solicited=True (solicited rating — standard for ECRA use).
    pd=None — external ratings carry no PD (PD is internal-rating only).
    """
    row = {
        "rating_reference": CCR_FLOOR1_RATING_REF,
        "counterparty_reference": CCR_FLOOR1_COUNTERPARTY_REF,
        "rating_type": CCR_FLOOR1_RATING_TYPE,
        "rating_agency": CCR_FLOOR1_RATING_AGENCY,
        "rating_value": CCR_FLOOR1_RATING_VALUE,
        "cqs": CCR_FLOOR1_RATING_CQS,
        "pd": None,
        "rating_date": CCR_FLOOR1_RATING_DATE,
        "is_solicited": True,
        "model_id": None,
        "is_short_term": False,
        "scope_type": None,
        "scope_id": None,
    }
    return pl.DataFrame([row], schema=dtypes_of(RATINGS_SCHEMA)).lazy()


def _build_empty_facilities() -> pl.LazyFrame:
    """Return a zero-row facilities LazyFrame (no traditional lending in this CCR-only bundle)."""
    return pl.LazyFrame(schema=dtypes_of(FACILITY_SCHEMA))


def _build_empty_loans() -> pl.LazyFrame:
    """Return a zero-row loans LazyFrame (no drawn loans in this CCR-only bundle)."""
    return pl.LazyFrame(schema=dtypes_of(LOAN_SCHEMA))


def _build_empty_facility_mappings() -> pl.LazyFrame:
    """Return a zero-row facility-mappings LazyFrame."""
    return pl.LazyFrame(schema=dtypes_of(FACILITY_MAPPING_SCHEMA))


def _build_empty_lending_mappings() -> pl.LazyFrame:
    """Return a zero-row lending-mappings LazyFrame."""
    return pl.LazyFrame(schema=dtypes_of(LENDING_MAPPING_SCHEMA))


def _build_ccr_floor1_raw_ccr_bundle() -> RawCCRBundle:
    """
    Assemble the RawCCRBundle for the B31-CCR-FLOOR-1 scenario.

    Composition:
        trades            — 1 row (T_CCR_1: 5y GBP IR derivative, V=10m, NS_CCR_1)
        netting_sets      — 1 row (NS_CCR_1: CP_CCR_1, enforceable, unmargined)
        margin_agreements — 0 rows (unmargined, no CSA)
        ccr_collateral    — 0 rows (no posted/received collateral)
    """
    return RawCCRBundle(
        trades=TradeBundle(trades=create_ccr_floor1_trades().lazy()),
        netting_sets=NettingSetBundle(netting_sets=create_ccr_floor1_netting_sets().lazy()),
        margin_agreements=MarginAgreementBundle(
            margin_agreements=create_ccr_floor1_margin_agreements().lazy()
        ),
        ccr_collateral=CCRCollateralBundle(ccr_collateral=create_ccr_floor1_collateral().lazy()),
    )


# ---------------------------------------------------------------------------
# Public bundle-assembly helper
# ---------------------------------------------------------------------------


def build_raw_data_bundle_ccr_floor1() -> RawDataBundle:
    """
    Assemble a complete RawDataBundle for the B31-CCR-FLOOR-1 scenario.

    Key responsibilities:
    - Provides CP_CCR_1 as an institution counterparty (entity_type="institution",
      CQS 2, GB) so the Classifier routes the CCR-derived synthetic exposure
      through SA-Institution (B31 Art. 120(2) Table 3 → 30% RW under ECRA).
    - Provides a matching external rating (CQS 2, S&P "A") so the full
      rating-inheritance pipeline resolves external_cqs correctly.
    - Zero-row facility / loan / contingent / mapping frames so the only
      exposure in the pipeline is the CCR-derived synthetic row.
    - No model_permissions: no IRB permission → pure SA path → U-TREA == S-TREA.
    - ccr is populated with a RawCCRBundle containing the single trade T_CCR_1
      (5y GBP IR derivative, MtM=10m) in netting set NS_CCR_1.

    Integration test usage:
        from tests.fixtures.ccr.golden_ccr_floor1 import build_raw_data_bundle_ccr_floor1
        data = build_raw_data_bundle_ccr_floor1()
        config = CalculationConfig.basel_3_1()
        config = replace(config, reporting_date=date(2030, 1, 1))
        result = pipeline_orchestrator.run_with_data(data, config)

    The test-writer must run this bundle through the pipeline to obtain the
    exact ead_ccr, risk_weight, sa_rwa, and OutputFloorSummary values.

    References:
        - PS1/26 Art. 92(2A) (output floor TREA)
        - PS1/26 Art. 120(2) Table 3 (B31 institution CQS 2 → 30% ECRA RW)
        - CRR Art. 274(2) (SA-CCR EAD = alpha × (RC + PFE))
    """
    return make_raw_bundle(
        counterparties=_build_cp_ccr_1_counterparty(),
        facilities=_build_empty_facilities(),
        loans=_build_empty_loans(),
        facility_mappings=_build_empty_facility_mappings(),
        lending_mappings=_build_empty_lending_mappings(),
        ratings=_build_cp_ccr_1_rating(),
        ccr=_build_ccr_floor1_raw_ccr_bundle(),
    )


# ---------------------------------------------------------------------------
# Save helper — canonical entry point for generate_all.py and standalone use.
# ---------------------------------------------------------------------------


def save_ccr_floor1_fixtures(output_dir: Path | None = None) -> dict[str, Path]:
    """
    Write all four B31-CCR-FLOOR-1 golden parquet files to *output_dir*.

    Files produced:
        ccr_floor1_trades.parquet           — 1 row (T_CCR_1, 5y GBP IR derivative)
        ccr_floor1_netting_sets.parquet     — 1 row (NS_CCR_1, CP_CCR_1)
        ccr_floor1_margin_agreements.parquet — 0 rows (unmargined)
        ccr_floor1_ccr_collateral.parquet   — 0 rows (no collateral)

    Args:
        output_dir: Target directory. Defaults to the directory containing
            this script (``tests/fixtures/ccr/``).

    Returns:
        Dict mapping artefact name to saved absolute Path.
    """
    if output_dir is None:
        output_dir = Path(__file__).parent
    output_dir.mkdir(parents=True, exist_ok=True)

    artefacts: list[tuple[str, pl.DataFrame]] = [
        ("ccr_floor1_trades", create_ccr_floor1_trades()),
        ("ccr_floor1_netting_sets", create_ccr_floor1_netting_sets()),
        ("ccr_floor1_margin_agreements", create_ccr_floor1_margin_agreements()),
        ("ccr_floor1_ccr_collateral", create_ccr_floor1_collateral()),
    ]

    saved: dict[str, Path] = {}
    for name, df in artefacts:
        path = output_dir / f"{name}.parquet"
        df.write_parquet(path)
        saved[name] = path

    return saved


def main() -> None:
    """Entry point for standalone generation and pipeline smoke-check."""
    saved = save_ccr_floor1_fixtures()
    print("B31-CCR-FLOOR-1 golden fixture generation complete")
    print("-" * 70)
    for name, path in saved.items():
        df = pl.read_parquet(path)
        print(f"  {name:<35} {len(df):>2} row(s)  {len(df.columns):>2} cols  ->  {path.name}")
    print("-" * 70)
    print("Scenario: B31-CCR-FLOOR-1 — SA-only CCR portfolio output floor pin")
    print(
        f"  Trade:       {CCR_FLOOR1_TRADE_ID} (asset_class={CCR_FLOOR1_ASSET_CLASS!r},"
        f" notional={CCR_FLOOR1_NOTIONAL:,.0f} {CCR_FLOOR1_CURRENCY}, V={CCR_FLOOR1_MTM:,.0f})"
    )
    print(
        f"  Netting set: {CCR_FLOOR1_NETTING_SET_ID} -> {CCR_FLOOR1_COUNTERPARTY_REF}"
        f" (enforceable={CCR_FLOOR1_IS_LEGALLY_ENFORCEABLE},"
        f" margined={CCR_FLOOR1_IS_MARGINED})"
    )
    print(f"  Reporting date: {CCR_FLOOR1_REPORTING_DATE} (Basel 3.1, floor 72.5%)")
    print(f"  Expected B31 institution CQS 2 RW: {CCR_FLOOR1_EXPECTED_B31_INSTITUTION_CQS2_RW:.0%}")


if __name__ == "__main__":
    main()
